/**
 * Forces FormEngine visible→hidden input sync on every page-wizard button
 * pointerdown. The v14 wizard reads FormData (which only sees hidden mirrors)
 * and filters out empty values; without this guard, clicking "Next" before
 * `change`/blur has propagated drops the user's typed values silently.
 */
class PageWizardGuard {
    constructor() {
        document.addEventListener('pointerdown', this.handlePointerDown, true);
    }

    private readonly handlePointerDown = (event: PointerEvent): void => {
        const target = event.target;
        if (!(target instanceof Element)) {
            return;
        }
        const wizard = target.closest('typo3-backend-page-wizard');
        if (!wizard) {
            return;
        }
        if (!target.closest('button')) {
            return;
        }
        const form = wizard.querySelector<HTMLFormElement>('form[name="editform"]');
        if (!form) {
            return;
        }
        this.commitVisibleFormEngineValues(form);
    };

    private commitVisibleFormEngineValues(form: HTMLFormElement): void {
        const fields = form.querySelectorAll<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>(
            '[data-formengine-input-name]',
        );
        for (const field of fields) {
            if (field instanceof HTMLInputElement && field.type === 'hidden') {
                continue;
            }
            field.dispatchEvent(new Event('change', { bubbles: true }));
        }
    }
}

export { PageWizardGuard };
export default new PageWizardGuard();
